using Microsoft.ML;
using Microsoft.ML.Data;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public sealed class TicketClassifierService
{
    private readonly MLContext _mlContext;
    private readonly string _dataPath;
    private ITransformer? _model;
    private PredictionEngine<TicketData, TicketPrediction>? _predictionEngine;
    private string[] _classLabels = [];

    public bool IsTrained => _model is not null;

    public TicketClassifierService(IWebHostEnvironment env)
    {
        _mlContext = new MLContext(seed: 42);
        _dataPath = Path.Combine(env.ContentRootPath, "Data", "tickets.csv");
    }

    /// <summary>
    /// Trains the multiclass classification model from the CSV data.
    /// </summary>
    public void Train()
    {
        var dataView = _mlContext.Data.LoadFromTextFile<TicketData>(
            _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var pipeline = _mlContext.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketData.Category))
            .Append(_mlContext.Transforms.Text.FeaturizeText(
                "SubjectFeaturized", nameof(TicketData.Subject)))
            .Append(_mlContext.Transforms.Text.FeaturizeText(
                "DescriptionFeaturized", nameof(TicketData.Description)))
            .Append(_mlContext.Transforms.Concatenate("Features",
                "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketData.Priority)))
            .Append(_mlContext.Transforms.NormalizeMinMax("Features"))
            .AppendCacheCheckpoint(_mlContext)
            .Append(_mlContext.MulticlassClassification.Trainers
                .SdcaMaximumEntropy("Label", "Features"))
            .Append(_mlContext.Transforms.Conversion
                .MapKeyToValue("PredictedLabel"));

        _model = pipeline.Fit(dataView);

        // Cache the class labels for confidence-score mapping.
        var labelColumn = _model.GetOutputSchema(dataView.Schema)["Label"];
        var labelBuffer = new VBuffer<ReadOnlyMemory<char>>();
        labelColumn.GetKeyValues(ref labelBuffer);
        _classLabels = labelBuffer.DenseValues().Select(v => v.ToString()).ToArray();

        _predictionEngine = _mlContext.Model
            .CreatePredictionEngine<TicketData, TicketPrediction>(_model);
    }

    /// <summary>
    /// Evaluates the model using cross-validation on the full dataset.
    /// </summary>
    public EvaluationResult Evaluate()
    {
        EnsureTrained();

        var dataView = _mlContext.Data.LoadFromTextFile<TicketData>(
            _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        // Re-apply label mapping so the evaluation data has the Label column.
        var predictions = _model!.Transform(dataView);
        var metrics = _mlContext.MulticlassClassification.Evaluate(predictions, "Label");

        var result = new EvaluationResult
        {
            MacroAccuracy = metrics.MacroAccuracy,
            MicroAccuracy = metrics.MicroAccuracy,
            LogLoss = metrics.LogLoss,
            LogLossReduction = metrics.LogLossReduction,
        };

        for (var i = 0; i < metrics.PerClassLogLoss.Count; i++)
        {
            var className = i < _classLabels.Length ? _classLabels[i] : $"Class{i}";
            result.PerClassMetrics.Add(new PerClassMetric
            {
                ClassName = className,
                Precision = metrics.ConfusionMatrix.PerClassPrecision[i],
                Recall = metrics.ConfusionMatrix.PerClassRecall[i],
                F1Score = 2.0 * metrics.ConfusionMatrix.PerClassPrecision[i]
                              * metrics.ConfusionMatrix.PerClassRecall[i]
                         / (metrics.ConfusionMatrix.PerClassPrecision[i]
                              + metrics.ConfusionMatrix.PerClassRecall[i]),
            });
        }

        return result;
    }

    /// <summary>
    /// Predicts the category for a single ticket.
    /// </summary>
    public ClassificationResult Predict(TicketRequest request)
    {
        EnsureTrained();

        var input = new TicketData
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority,
        };

        var prediction = _predictionEngine!.Predict(input);

        var confidenceScores = new Dictionary<string, float>();
        for (var i = 0; i < prediction.Score.Length && i < _classLabels.Length; i++)
        {
            confidenceScores[_classLabels[i]] = prediction.Score[i];
        }

        return new ClassificationResult
        {
            PredictedCategory = prediction.PredictedCategory,
            ConfidenceScores = confidenceScores,
        };
    }

    private void EnsureTrained()
    {
        if (!IsTrained)
            throw new InvalidOperationException(
                "Model has not been trained. Call POST /api/tickets/train first.");
    }
}

using Microsoft.AspNetCore.Mvc;
using TicketClassifier.Models;
using TicketClassifier.Services;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/tickets")]
public class TicketsController : ControllerBase
{
    private readonly TicketClassifierService _classifier;

    public TicketsController(TicketClassifierService classifier)
    {
        _classifier = classifier;
    }

    /// <summary>
    /// Trains (or re-trains) the ML model from the CSV dataset.
    /// </summary>
    [HttpPost("train")]
    public IActionResult Train()
    {
        _classifier.Train();
        return Ok(new { message = "Model trained successfully." });
    }

    /// <summary>
    /// Returns evaluation metrics for the trained model.
    /// </summary>
    [HttpGet("evaluate")]
    public ActionResult<EvaluationResult> Evaluate()
    {
        try
        {
            return Ok(_classifier.Evaluate());
        }
        catch (InvalidOperationException ex)
        {
            return BadRequest(new { error = ex.Message });
        }
    }

    /// <summary>
    /// Predicts the category for a support ticket.
    /// </summary>
    [HttpPost("classify")]
    public ActionResult<ClassificationResult> Classify([FromBody] TicketRequest request)
    {
        if (!ModelState.IsValid)
            return ValidationProblem();

        try
        {
            return Ok(_classifier.Predict(request));
        }
        catch (InvalidOperationException ex)
        {
            return BadRequest(new { error = ex.Message });
        }
    }
}

