+[ApiController]
+[Route("api/tickets")]
+public class TicketsController : ControllerBase
+{
+    private readonly TicketClassifierService _classifier;
+
+    public TicketsController(TicketClassifierService classifier)
+    {
+        _classifier = classifier;
+    }
+
+    /// <summary>
+    /// Trains (or re-trains) the ML model from the CSV dataset.
+    /// </summary>
+    [HttpPost("train")]
+    public IActionResult Train()
+    {
+        _classifier.Train();
+        return Ok(new { message = "Model trained successfully." });
+    }
+
+    /// <summary>
+    /// Returns evaluation metrics for the trained model.
+    /// </summary>
+    [HttpGet("evaluate")]
+    public ActionResult<EvaluationResult> Evaluate()
+    {
+        try
+        {
+            return Ok(_classifier.Evaluate());
+        }
+        catch (InvalidOperationException ex)
+        {
+            return BadRequest(new { error = ex.Message });
+        }
+    }
+
+    /// <summary>
+    /// Predicts the category for a support ticket.
+    /// </summary>
+    [HttpPost("classify")]
+    public ActionResult<ClassificationResult> Classify([FromBody] TicketRequest request)
+    {
+        if (!ModelState.IsValid)
+            return ValidationProblem();
+
+        try
+        {
+            return Ok(_classifier.Predict(request));
+        }
+        catch (InvalidOperationException ex)
+        {
+            return BadRequest(new { error = ex.Message });
+        }
+    }
+}
